import { baseApi } from "@app/store";

import type { KtpCatalog, KtpTopicInput } from "@entities/ktp/lib/types";

interface ApiResponse<T> {
  data: T;
}

export const {
  useGetKtpCatalogQuery,
  useUpsertKtpMetaMutation,
  useAddKtpTopicMutation,
  useUpdateKtpTopicMutation,
  useDeleteKtpTopicMutation,
  useReorderKtpTopicsMutation,
  useImportKtpTopicsMutation,
} = baseApi.injectEndpoints({
  endpoints: builder => ({
    getKtpCatalog: builder.query<KtpCatalog | null, string>({
      query: subjectId => `/ktp/${subjectId}`,
      transformResponse: (res: ApiResponse<KtpCatalog | null>) => res.data,
      providesTags: (_r, _e, subjectId) => [{ type: "Ktp", id: subjectId }],
    }),
    upsertKtpMeta: builder.mutation<KtpCatalog, { subjectId: string; year?: number; version?: number }>({
      query: ({ subjectId, ...body }) => ({ url: `/ktp/${subjectId}`, method: "POST", body }),
      transformResponse: (res: ApiResponse<KtpCatalog>) => res.data,
      invalidatesTags: (_r, _e, { subjectId }) => [{ type: "Ktp", id: subjectId }],
    }),
    addKtpTopic: builder.mutation<KtpCatalog, { subjectId: string; body: KtpTopicInput }>({
      query: ({ subjectId, body }) => ({ url: `/ktp/${subjectId}/topics`, method: "POST", body }),
      transformResponse: (res: ApiResponse<KtpCatalog>) => res.data,
      invalidatesTags: (_r, _e, { subjectId }) => [{ type: "Ktp", id: subjectId }],
    }),
    updateKtpTopic: builder.mutation<
      KtpCatalog,
      { subjectId: string; topicId: string; body: Partial<KtpTopicInput> }
    >({
      query: ({ subjectId, topicId, body }) => ({
        url: `/ktp/${subjectId}/topics/${topicId}`,
        method: "PATCH",
        body,
      }),
      transformResponse: (res: ApiResponse<KtpCatalog>) => res.data,
      invalidatesTags: (_r, _e, { subjectId }) => [{ type: "Ktp", id: subjectId }],
    }),
    deleteKtpTopic: builder.mutation<KtpCatalog, { subjectId: string; topicId: string }>({
      query: ({ subjectId, topicId }) => ({
        url: `/ktp/${subjectId}/topics/${topicId}`,
        method: "DELETE",
      }),
      transformResponse: (res: ApiResponse<KtpCatalog>) => res.data,
      invalidatesTags: (_r, _e, { subjectId }) => [{ type: "Ktp", id: subjectId }],
    }),
    reorderKtpTopics: builder.mutation<KtpCatalog, { subjectId: string; orderedTopicIds: string[] }>({
      query: ({ subjectId, orderedTopicIds }) => ({
        url: `/ktp/${subjectId}/reorder`,
        method: "POST",
        body: { orderedTopicIds },
      }),
      transformResponse: (res: ApiResponse<KtpCatalog>) => res.data,
      invalidatesTags: (_r, _e, { subjectId }) => [{ type: "Ktp", id: subjectId }],
    }),
    importKtpTopics: builder.mutation<
      KtpCatalog,
      { subjectId: string; topics: KtpTopicInput[]; year?: number; version?: number; replace?: boolean }
    >({
      query: ({ subjectId, ...body }) => ({ url: `/ktp/${subjectId}/import`, method: "POST", body }),
      transformResponse: (res: ApiResponse<KtpCatalog>) => res.data,
      invalidatesTags: (_r, _e, { subjectId }) => [{ type: "Ktp", id: subjectId }],
    }),
  }),
});

